  },
};

const componentSchemaOneOf = knownTypes.map(type => ({
  if: { properties: { type: { const: type } } },
  then: {
    properties: {
      type: { const: type },
      props: componentPropsSchemas[type] || { type: 'object' as const },
      visible: conditionalSchema,
    },
    required: ['type', 'props'],
  },
}));

export const sduiScreenSchema = {
  $schema: 'http://json-schema.org/draft-07/schema#',
  type: 'object',
  properties: {
    id: { type: 'string' },
    context: { type: 'object' },
    header: {
      type: 'object',
      properties: {
        type: { type: 'string', enum: knownTypes },
        props: { type: 'object' },
        visible: conditionalSchema,
      },
      required: ['type', 'props'],
    },
    body: {
      type: 'array',
      items: {
        type: 'object',
        properties: {
          type: { type: 'string' },
          props: { type: 'object' },
          visible: conditionalSchema,
        },
        required: ['type', 'props'],
        allOf: componentSchemaOneOf,
      },
    },
    footer: {
      type: 'object',
      properties: {
        type: { type: 'string', enum: knownTypes },
        props: { type: 'object' },
        visible: conditionalSchema,
      },
      required: ['type', 'props'],
    },
  },
  required: ['id', 'body'],
};

export { knownTypes, componentPropsSchemas };

