import React from 'react';
import { Box, Icon, Text } from '@semparar/design-system-app';
import type { SDUIComponentProps, SDUIContext } from '../models';

interface EmptyStateProps extends SDUIComponentProps {
  icon: string;
  iconColor?: string;
  bgColor?: string;
  title: string;
  description?: string;
}

export default function EmptyStateAdapter({
  props,
}: {
  props: EmptyStateProps;
  context: SDUIContext;
}) {
  const {
    icon,
    iconColor = 'INTENSE_COLOR_03',
    bgColor = 'BRAND_COMPLEMENT_02',
    title,
    description,
  } = props;

  return (
    <Box align="center" pd="innerLarger" justify="center" mt="larger">
      <Box
        width={80}
        height={80}
        align="center"
        justify="center"
        bgColor={bgColor}
        style={{ borderRadius: 40 }}
      >
        <Icon name={String(icon)} size="lg" color={iconColor} />
      </Box>
      <Text type="paragraphXXXL" mt="nano" align="center">
        {title}
      </Text>
      {description ? (
        <Text type="paragraphLG" align="center" mt="nano">
          {description}
        </Text>
      ) : null}
    </Box>
  );
}

