import React, { useState } from 'react';
import { View, Pressable } from 'react-native';
import { Box, Text, SeparatorHorizontal } from '@semparar/design-system-app';
import type { SDUIComponentProps, SDUIContext } from '../models';

interface TabItem {
  id: number;
  title: string;
}

interface TabBarProps extends SDUIComponentProps {
  tabs: TabItem[];
  mt?: string;
  mb?: string;
  ml?: string;
}

export default function TabBarAdapter({
  props,
}: {
  props: TabBarProps;
  context: SDUIContext;
}) {
  const { tabs = [], ml = 'smaller', mt, mb } = props;
  const [activeTab, setActiveTab] = useState(0);

  return (
    <Box mt={mt} mb={mb}>
      <View style={{ flexDirection: 'row', marginLeft: ml === 'smaller' ? 12 : 0, marginBottom: 4 }}>
        {tabs.map((tab: TabItem, idx: number) => {
          const isActive = idx === activeTab;
          return (
            <Pressable
              key={tab.id ?? idx}
              onPress={() => setActiveTab(idx)}
              style={{ marginRight: 16, paddingBottom: 8, borderBottomWidth: isActive ? 2 : 0, borderBottomColor: '#E91E63' }}
            >
              <Text
                type={isActive ? 'subtitleXXL' : 'paragraphMD'}
                color={isActive ? 'INTENSE_COLOR_05' : 'INTENSE_COLOR_03'}
              >
                {tab.title}
              </Text>
            </Pressable>
          );
        })}
      </View>
      <SeparatorHorizontal width="100%" height={1} borderColor="BRAND_COMPLEMENT_02" />
    </Box>
  );
}

