  },
  {
    id: 'alert',
    label: 'Alert',
    category: 'component',
    description: 'Info/warning/error alert box',
    json: JSON.stringify({ type: 'alert', props: { label: 'Informação importante', type: 'info', icon: 'icon-info' } }, null, 2),
  },
  {
    id: 'list_text_icon',
    label: 'List Text Icon',
    category: 'component',
    description: 'List of items with icon + description',
    json: JSON.stringify({ type: 'list_text_icon', props: { items: [{ icon: 'icon-check', description: 'Item description' }] } }, null, 2),
  },
  {
    id: 'separator',
