    category: 'component',
    description: 'Horizontal line divider',
    json: JSON.stringify({ type: 'separator', props: { mt: 'sm', mb: 'sm' } }, null, 2),
  },
  {
    id: 'icon_text_row',
    label: 'Icon Text Row',
    category: 'component',
    description: 'Row with icon and text side-by-side',
    json: JSON.stringify({ type: 'icon_text_row', props: { icon: 'icon-check', text: 'Description text', mb: 'sm' } }, null, 2),
  },
  {
    id: 'nav_header',
    label: 'Nav Header',
    category: 'component',
    description: 'Navigation header with back button',
    json: JSON.stringify({ type: 'nav_header', props: { title: 'Screen Title', showBack: true } }, null, 2),
  },
  {
    id: 'rich_text',
