  },

  // ─── Structure ───────────────────────────────────────────
  {
    id: 'visible_conditional',
    label: 'Conditional Visibility',
    category: 'structure',
    description: 'Show/hide component based on context',
    json: JSON.stringify({ type: 'text', props: { text: 'Conditional content' }, visible: { rule: { '==': [{ var: 'flags.showBanner' }, true] } } }, null, 2),
  },
  {
    id: 'body_item',
    label: 'Body Component',
    category: 'structure',
