        { type: 'link', props: { text: 'Exibir regras de uso', align: 'center', mt: 'sm' } },
      ],
      footer: { type: 'button', props: { text: 'Criar voucher', mt: 'md' } },
    }, null, 2),
  },
  {
    id: 'screen_summary',
    label: 'Voucher Summary',
    category: 'screen',
    description: 'Review confirmation before creating voucher',
    json: JSON.stringify({
      id: 'voucher-summary',
      context: {
        product: { name: 'Abastecimento' },
        selectedPoints: '5.000',
        selectedReais: 'R$ 50,00',
      },
      header: { type: 'nav_header', props: { title: 'Resumo', showBack: true } },
      body: [
        { type: 'heading', props: { text: 'Confirme seu voucher', mb: 'md' } },
        { type: 'text', props: { text: '{{product.name}}', type: 'subtitleXXL', mb: 'sm' } },
