        { type: 'text', props: { text: '{{selectedReais}}', mb: 'sm' } },
        { type: 'alert', props: { label: 'O voucher será criado e estará disponível em Meus Vouchers', type: 'info', icon: 'icon-info' } },
      ],
      footer: { type: 'button', props: { text: 'Criar voucher', mt: 'md' } },
    }, null, 2),
  },
  {
    id: 'screen_conclusion',
    label: 'Voucher Conclusion',
    category: 'screen',
    description: 'Success screen after voucher creation',
    json: JSON.stringify({
      id: 'voucher-conclusion',
      context: { product: { name: 'Abastecimento' } },
      body: [
        { type: 'icon_text_row', props: { icon: 'icon-check-circle', iconColor: '#4caf50', text: '', mb: 'md' } },
        { type: 'heading', props: { text: 'O voucher foi criado!', mb: 'sm' } },
        { type: 'text', props: { text: 'Seu voucher de {{product.name}} está disponível em Meus Vouchers', mb: 'md', align: 'center' } },
      ],
      footer: { type: 'button', props: { text: 'Ir para o início', mt: 'md' } },
    }, null, 2),
  },
  {
    id: 'screen_rules',
    label: 'Voucher Rules',
    category: 'screen',
    description: 'Rules of use screen for voucher',
    json: JSON.stringify({
      id: 'voucher-rules',
      context: { product: { name: 'Abastecimento' } },
      header: { type: 'nav_header', props: { title: 'Regras de uso', showBack: true } },
      body: [
        { type: 'section_heading', props: { text: 'Regras de uso — {{product.name}}', mb: 'md' } },
        { type: 'icon_text_row', props: { icon: 'icon-check', text: 'O voucher tem validade de 30 dias', mb: 'sm' } },
        { type: 'icon_text_row', props: { icon: 'icon-check', text: 'Pode ser utilizado parcialmente', mb: 'sm' } },
        { type: 'icon_text_row', props: { icon: 'icon-check', text: 'Válido apenas para {{product.name}}', mb: 'sm' } },
      ],
    }, null, 2),
  },
];

const categoryLabels: Record<SDUISnippet['category'], string> = {
  component: 'Components',
  structure: 'Structure',
  screen: 'Screen Templates',
};

export function getSnippetsByCategory(): Array<{
  category: SDUISnippet['category'];
  label: string;
  items: SDUISnippet[];
}> {
  const groups = new Map<SDUISnippet['category'], SDUISnippet[]>();
  for (const s of sduiSnippets) {
    const list = groups.get(s.category) ?? [];
    list.push(s);
    groups.set(s.category, list);
  }
  return (['component', 'structure', 'screen'] as const).map(cat => ({
    category: cat,
    label: categoryLabels[cat],
    items: groups.get(cat) ?? [],
  }));
}

export function filterSnippets(query: string): SDUISnippet[] {
  if (!query.trim()) return sduiSnippets;
  const q = query.toLowerCase();
  return sduiSnippets.filter(
    s =>
      s.label.toLowerCase().includes(q) ||
      s.description.toLowerCase().includes(q) ||
      s.id.includes(q) ||
      s.category.includes(q),
  );
}

