      ],
    }, null, 2),
  },
];

const categoryLabels: Record<SDUISnippet['category'], string> = {
  component: 'Components',
  structure: 'Structure',
  screen: 'Screen Templates',
};

export function getSnippetsByCategory(): Array<{
  category: SDUISnippet['category'];
  label: string;
  items: SDUISnippet[];
}> {
  const groups = new Map<SDUISnippet['category'], SDUISnippet[]>();
  for (const s of sduiSnippets) {
    const list = groups.get(s.category) ?? [];
    list.push(s);
    groups.set(s.category, list);
  }
  return (['component', 'structure', 'screen'] as const).map(cat => ({
    category: cat,
    label: categoryLabels[cat],
    items: groups.get(cat) ?? [],
  }));
}

export function filterSnippets(query: string): SDUISnippet[] {
  if (!query.trim()) return sduiSnippets;
  const q = query.toLowerCase();
  return sduiSnippets.filter(
    s =>
      s.label.toLowerCase().includes(q) ||
      s.description.toLowerCase().includes(q) ||
      s.id.includes(q) ||
      s.category.includes(q),
  );
}

