(async () => {
  const browser = await chromium.launch();
  const page = await browser.newPage({ viewport: { width: 1280, height: 900 } });

  // Demo story
  await page.goto('http://localhost:6006/iframe.html?id=sdui-extract-history--demo&viewMode=story');
  await page.waitForTimeout(3000);
  await page.screenshot({ path: '.storybook/screenshots/sdui-extract-demo.png', fullPage: true });
  console.log('Screenshot: sdui-extract-demo.png');

  // Comparison story
  await page.goto('http://localhost:6006/iframe.html?id=sdui-extract-history--comparison&viewMode=story');
  await page.waitForTimeout(3000);
  await page.screenshot({ path: '.storybook/screenshots/sdui-extract-comparison.png', fullPage: true });
  console.log('Screenshot: sdui-extract-comparison.png');

  await browser.close();
  console.log('Done');
})();
